#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define FLT_MAX 3.40282347e+38f

inline float euclid_dist_2(__global float *pt1,
                           __global float *pt2,
                           int numdims)
{
    float ans = 0.0f;
    for (int i = 0; i < numdims; i++) {
        float diff = pt1[i] - pt2[i];
        ans += diff * diff;
    }
    return ans;
}

inline int find_nearest_point(__global float *pt,
                              int nfeatures,
                              __global float *pts,
                              int npts)
{
    int index = 0;
    float min_dist = FLT_MAX;

    for (int i = 0; i < npts; i++) {
        float dist = 0.0f;
        for (int d = 0; d < nfeatures; d++) {
            float diff = pt[d] - pts[i * nfeatures + d];
            dist += diff * diff;
        }
        if (dist < min_dist) {
            min_dist = dist;
            index = i;
        }
    }
    return index;
}

// Kernel to assign points to nearest cluster and accumulate partial sums and counts
__kernel void assign_clusters(
    __global float *features,          // flattened features array [npoints * nfeatures]
    int nfeatures,
    int npoints,
    __global float *clusters,          // flattened clusters array [nclusters * nfeatures]
    int nclusters,
    __global int *membership,          // membership array [npoints]
    __global float *partial_new_centers,  // partial sums [nthreads * nclusters * nfeatures]
    __global int *partial_new_centers_len // partial counts [nthreads * nclusters]
)
{
    int gid = get_global_id(0);
    int tid = get_local_id(0) + get_group_id(0) * get_local_size(0); // global thread id
    if (gid >= npoints) return;

    __global float *pt = &features[gid * nfeatures];
    int nearest = 0;
    float min_dist = FLT_MAX;

    // Find nearest cluster center
    for (int c = 0; c < nclusters; c++) {
        float dist = 0.0f;
        for (int d = 0; d < nfeatures; d++) {
            float diff = pt[d] - clusters[c * nfeatures + d];
            dist += diff * diff;
        }
        if (dist < min_dist) {
            min_dist = dist;
            nearest = c;
        }
    }

    membership[gid] = nearest;

    // Accumulate partial sums and counts atomically
    int base_len_idx = tid * nclusters + nearest;
    atomic_inc(&partial_new_centers_len[base_len_idx]);

    int base_sum_idx = tid * nclusters * nfeatures + nearest * nfeatures;
    for (int d = 0; d < nfeatures; d++) {
        // Atomic add for floats is not standard in OpenCL 2.0
        // Use atomic_add if supported, else use atomic operations with integer conversion
        // Here, we assume atomic_add for floats supported (OpenCL 2.0)
        atomic_fetch_add(&partial_new_centers[base_sum_idx + d], pt[d]);
    }
}

// Kernel to sum partial results into new_centers and new_centers_len and reset partial buffers
__kernel void reduce_partial_results(
    int nthreads,
    int nclusters,
    int nfeatures,
    __global float *partial_new_centers,
    __global int *partial_new_centers_len,
    __global float *new_centers,
    __global int *new_centers_len
)
{
    int cid = get_global_id(0); // cluster id
    if (cid >= nclusters) return;

    int len_sum = 0;
    for (int t = 0; t < nthreads; t++) {
        len_sum += partial_new_centers_len[t * nclusters + cid];
        partial_new_centers_len[t * nclusters + cid] = 0;
    }
    new_centers_len[cid] = len_sum;

    for (int d = 0; d < nfeatures; d++) {
        float sum = 0.0f;
        for (int t = 0; t < nthreads; t++) {
            sum += partial_new_centers[t * nclusters * nfeatures + cid * nfeatures + d];
            partial_new_centers[t * nclusters * nfeatures + cid * nfeatures + d] = 0.0f;
        }
        new_centers[cid * nfeatures + d] = sum;
    }
}

// Kernel to compute updated cluster centers from new_centers / new_centers_len
__kernel void update_clusters(
    int nclusters,
    int nfeatures,
    __global float *clusters,
    __global float *new_centers,
    __global int *new_centers_len
)
{
    int cid = get_global_id(0);
    if (cid >= nclusters) return;

    int count = new_centers_len[cid];
    if (count > 0) {
        for (int d = 0; d < nfeatures; d++) {
            clusters[cid * nfeatures + d] = new_centers[cid * nfeatures + d] / (float)count;
        }
    }
}

// Kernel to compute delta: number of points with changed membership
__kernel void compute_delta(
    int npoints,
    __global int *membership,
    __global int *old_membership,
    __global int *delta_partial
)
{
    int gid = get_global_id(0);
    if (gid >= npoints) return;

    delta_partial[gid] = (membership[gid] != old_membership[gid]) ? 1 : 0;
}

// Kernel to copy membership to old_membership
__kernel void copy_membership(
    int npoints,
    __global int *membership,
    __global int *old_membership
)
{
    int gid = get_global_id(0);
    if (gid >= npoints) return;
    old_membership[gid] = membership[gid];
}
